async function savePods(pods) {
  try {
    await supabase.from("members").upsert({ id: "__pods__", data: { pods }, updated_at: new Date().toISOString() });
  } catch (e) { console.error("savePods error", e); }
}
async function loadPods() {
  try {
    const { data, error } = await supabase.from("members").select("data").eq("id", "__pods__").single();
    if (!error && data) {
      const raw = data.data?.pods || [];
      // Ensure every pod has a valid memberIds array (defensive against malformed data)
      return raw.map(p => ({ ...p, memberIds: Array.isArray(p.memberIds) ? p.memberIds : [] }));
    }
  } catch {}
  return [];
}

