// ─── Capacity Index Calculators ───────────────────────────────────────────────
// VO2 Max 12-Tier System (Eric's updated table — age + sex adjusted, ml/kg/min)
// Tiers: Critical=8, VeryLow=16, Low=24, Developing=33, Foundation=42,
//        Emerging=51, Building=58, Strong=66, Advanced=74, Durable=82, Elite=90, Peak=99
// Each entry: [minVO2 (inclusive), tierFloorScore] — listed highest first.
// Scoring uses linear interpolation within each band so every VO2 point
// produces a unique score. The top tier (Peak) is flat at 99.
// The bottom tier (Critical) is flat at 8 — no interpolation below VeryLow floor.
function getVO2Score(vo2, age, sex) {
  const tables = {
    male: {
      "20-29": [[64,99],[60,90],[57,82],[54,74],[51,66],[48,58],[45,51],[41,42],[37,33],[33,24],[28,16],[0,8]],
      "30-39": [[62,99],[58,90],[55,82],[52,74],[49,66],[46,58],[43,51],[39,42],[35,33],[31,24],[26,16],[0,8]],
      "40-49": [[59,99],[55,90],[52,82],[49,74],[46,66],[43,58],[40,51],[36,42],[32,33],[28,24],[24,16],[0,8]],
      "50-59": [[56,99],[52,90],[49,82],[46,74],[43,66],[40,58],[37,51],[34,42],[30,33],[26,24],[22,16],[0,8]],
      "60-69": [[51,99],[47,90],[44,82],[41,74],[38,66],[35,58],[32,51],[29,42],[26,33],[23,24],[20,16],[0,8]],
      "70-79": [[48,99],[45,90],[42,82],[39,74],[36,66],[33,58],[30,51],[27,42],[24,33],[21,24],[18,16],[0,8]],
      "80-89": [[46,99],[43,90],[40,82],[37,74],[34,66],[31,58],[28,51],[25,42],[22,33],[19,24],[16,16],[0,8]],
    },
    female: {
      "20-29": [[55,99],[51,90],[48,82],[45,74],[42,66],[39,58],[36,51],[32,42],[28,33],[24,24],[20,16],[0,8]],
      "30-39": [[51,99],[48,90],[45,82],[42,74],[39,66],[36,58],[33,51],[30,42],[26,33],[22,24],[18,16],[0,8]],
      "40-49": [[49,99],[46,90],[43,82],[40,74],[37,66],[34,58],[31,51],[28,42],[24,33],[20,24],[17,16],[0,8]],
      "50-59": [[46,99],[43,90],[40,82],[37,74],[34,66],[31,58],[28,51],[25,42],[22,33],[19,24],[15,16],[0,8]],
      "60-69": [[44,99],[41,90],[38,82],[35,74],[32,66],[29,58],[26,51],[23,42],[20,33],[17,24],[14,16],[0,8]],
      "70-79": [[43,99],[40,90],[37,82],[34,74],[31,66],[28,58],[25,51],[22,42],[19,33],[16,24],[13,16],[0,8]],
      "80-89": [[42,99],[39,90],[36,82],[33,74],[30,66],[27,58],[24,51],[21,42],[18,33],[15,24],[12,16],[0,8]],
    }
  };
  const ageKey = age < 30 ? "20-29" : age < 40 ? "30-39" : age < 50 ? "40-49" : age < 60 ? "50-59" : age < 70 ? "60-69" : age < 80 ? "70-79" : "80-89";
  const chart = tables[sex]?.[ageKey] || tables.male["40-49"];
  for (let i = 0; i < chart.length; i++) {
    const [bandMin, bandScore] = chart[i];
    if (vo2 >= bandMin) {
      if (i === 0) return bandScore;                  // Peak tier — flat 99
      if (i === chart.length - 1) return bandScore;  // Critical tier — flat 8
      const [nextMin, nextScore] = chart[i - 1];
      const posInBand = vo2 - bandMin;
      const bandWidth = nextMin - bandMin;
      const scoreRange = nextScore - bandScore;
      return Math.round(bandScore + (posInBand / bandWidth) * scoreRange);
    }
  }
  return 8;
}

function getGripScore(grip, bw, age, sex) {
  const gbr = grip / bw; // grip-to-bodyweight ratio

  // GBSC Robust Grip Standards — Jamar (Age + Bodyweight Adjusted, 12 tiers)
  // Each entry: [min GBR (inclusive), score]
  // T1 Critical=8, T2 Very Low=16, T3 Low=24, T4 Below Avg=32, T5 Avg-=40,
  // T6 Average=50, T7 Avg+=58, T8 Strong=66, T9 Very Strong=74,
  // T10 Elite=82, T11 Top 1-3%=90, T12 Freak=98
  const tables = {
    male: {
      "18-34": [[0.91,98],[0.83,90],[0.76,82],[0.71,74],[0.66,66],[0.61,58],[0.56,50],[0.51,40],[0.46,32],[0.41,24],[0.36,16],[0,8]],
      "35-44": [[0.89,98],[0.81,90],[0.74,82],[0.69,74],[0.64,66],[0.59,58],[0.54,50],[0.49,40],[0.44,32],[0.39,24],[0.34,16],[0,8]],
      "45-54": [[0.87,98],[0.79,90],[0.72,82],[0.67,74],[0.62,66],[0.57,58],[0.52,50],[0.47,40],[0.42,32],[0.37,24],[0.32,16],[0,8]],
      "55-64": [[0.85,98],[0.77,90],[0.70,82],[0.65,74],[0.60,66],[0.55,58],[0.50,50],[0.45,40],[0.40,32],[0.35,24],[0.30,16],[0,8]],
      "65+":   [[0.83,98],[0.75,90],[0.68,82],[0.63,74],[0.58,66],[0.53,58],[0.48,50],[0.43,40],[0.38,32],[0.33,24],[0.28,16],[0,8]],
    },
    female: {
      "18-34": [[0.73,98],[0.65,90],[0.58,82],[0.54,74],[0.50,66],[0.46,58],[0.42,50],[0.38,40],[0.34,32],[0.30,24],[0.26,16],[0,8]],
      "35-44": [[0.72,98],[0.64,90],[0.57,82],[0.53,74],[0.49,66],[0.45,58],[0.41,50],[0.37,40],[0.33,32],[0.29,24],[0.25,16],[0,8]],
      "45-54": [[0.71,98],[0.63,90],[0.56,82],[0.52,74],[0.48,66],[0.44,58],[0.40,50],[0.36,40],[0.32,32],[0.28,24],[0.24,16],[0,8]],
      "55-64": [[0.69,98],[0.61,90],[0.54,82],[0.50,74],[0.46,66],[0.42,58],[0.38,50],[0.34,40],[0.30,32],[0.26,24],[0.22,16],[0,8]],
      "65+":   [[0.67,98],[0.59,90],[0.52,82],[0.48,74],[0.44,66],[0.40,58],[0.36,50],[0.32,40],[0.28,32],[0.24,24],[0.20,16],[0,8]],
    }
  };

  const ageKey = age < 35 ? "18-34" : age < 45 ? "35-44" : age < 55 ? "45-54" : age < 65 ? "55-64" : "65+";
  const chart = tables[sex]?.[ageKey] || tables.male["45-54"];
  for (let i = 0; i < chart.length; i++) {
    const [bandMin, bandScore] = chart[i];
    if (gbr >= bandMin) {
      if (i === 0) return bandScore;                 // Top tier (Freak) — flat 98
      if (i === chart.length - 1) return bandScore; // Bottom tier (Critical) — flat 8
      const [nextMin, nextScore] = chart[i - 1];
      const posInBand = gbr - bandMin;
      const bandWidth = nextMin - bandMin;
      const scoreRange = nextScore - bandScore;
      return Math.round(bandScore + (posInBand / bandWidth) * scoreRange);
    }
  }
  return 8;
}

// ─── Declared Week Engine ─────────────────────────────────────────────────────
function getDeclaredWeek(allChecks) {
  const nonBaseline = (allChecks || []).filter(c => c && !c.isBaseline);
  const latest = nonBaseline[nonBaseline.length - 1];
  if (!latest) return null;

  const weekCount = nonBaseline.length;
  const score = latest.score;

  // Pull signals from latest check-in
  const sleep    = parseInt(latest.sleepQuality) || 0;
  const energy   = parseInt(latest.energyLevel) || 0;
  const recovery = parseInt(latest.physicalRecovery) || 0;
  const hasMajorDisruption = latest.disruption === "Major disruption";
  const hasSomeDisruption  = latest.disruption === "Some disruption";
  const workouts = { "0": 0, "1": 1, "2": 2, "3": 3, "4+": 4 }[latest.workouts] ?? 0;

  // Recovery signal: avg of sleep/energy/recovery (out of 5)
  const recoverySignal = (sleep + energy + recovery) / 3;

  // Trend signals (week 3+)
  let consistencyTrend = null;
  let recoveryTrend = null;
  if (weekCount >= 3) {
    const prev2 = nonBaseline.slice(-3, -1);
    const avgPrevScore = prev2.reduce((s, c) => s + c.score, 0) / prev2.length;
    consistencyTrend = score >= avgPrevScore ? "up" : "down";
    const avgPrevRecovery = prev2.reduce((s, c) => ((parseInt(c.sleepQuality)||0) + (parseInt(c.energyLevel)||0) + (parseInt(c.physicalRecovery)||0)) / 3, 0) / prev2.length;
    recoveryTrend = recoverySignal >= avgPrevRecovery ? "up" : "down";
  }

  // ── Declaration logic ──────────────────────────────────────────────────────
  // Stabilizer bias: disruption, poor recovery, low score, low workouts
  const stabilizerSignals = [
    hasMajorDisruption,
    hasSomeDisruption && recoverySignal < 2.5,
    recoverySignal < 2,
    score < 55,
    workouts < 2,
    consistencyTrend === "down" && recoveryTrend === "down",
  ].filter(Boolean).length;

  // Performer safeguard: requires 2 of 3 strong signals
  const performerSignals = [
    recoverySignal >= 3.5,
    score >= 80,
    consistencyTrend === "up",
  ].filter(Boolean).length;
  const performerUnlocked = performerSignals >= 2;

  // Performer: high score, good recovery, no disruption, safeguard met
  const isPerformer = performerUnlocked && score >= 80 && recoverySignal >= 3.5 && !hasMajorDisruption && workouts >= 3;

  // Stabilizer: clear signal
  const isStabilizer = stabilizerSignals >= 2 || score < 55 || hasMajorDisruption;

  let role;
  if (isStabilizer) role = "Stabilizer";
  else if (isPerformer) role = "Performer";
  else role = "Builder";

  // ── Reason lines ───────────────────────────────────────────────────────────
  // Week 1-2: score-based, honest about thin data
  // Week 3+: can reference trends
  const reasonLines = {
    Stabilizer: weekCount < 3
      ? (hasMajorDisruption ? "Looks like a heavy week — keeping things simple." : recoverySignal < 2.5 ? "Recovery signals suggest holding steady this week." : "Based on your check-in today, this is a consistency week.")
      : (hasMajorDisruption ? "Disruption in your recent pattern — protecting consistency." : recoveryTrend === "down" ? "Recovery has dipped recently — we're holding steady." : "Life looked heavier recently — keep this week simple."),
    Builder: weekCount < 3
      ? "Solid signals from your check-in — time to build with control."
      : (consistencyTrend === "up" ? "Your recent trend supports a stronger week." : "Consistency and recovery look good — time to build."),
    Performer: weekCount < 3
      ? "Strong signals across the board — you're ready for a higher-output week."
      : "Consistency and recovery are both strong — perform with control.",
  };

  const ROLE_CONFIG = {
    Stabilizer: {
      color: "#8A94A6", bg: "#F4F6F8", accent: "#C7CED6", textSupport: "#5F6B7A", iconName: "stabilizer",
      subtext: "Hold the line.",
      targets: [
        { label: "Training",  value: "2 workouts" },
        { label: "Engine",    value: "60 min total aerobic work" },
        { label: "Nutrition", value: "Protein in 2+ meals most days" },
        { label: "Recovery",  value: "3–4 nights of 7+ hours · 1–2 recovery actions" },
      ],
      tightTargets: [
        { label: "Training",  value: "1 workout" },
        { label: "Movement",  value: "30 min total movement" },
        { label: "Nutrition", value: "Protein once daily" },
        { label: "Recovery",  value: "Prioritize sleep when possible" },
      ],
      moreTargets: [
        { label: "Option A", value: "Add 1 extra walk" },
        { label: "Option B", value: "Or add 1 short session" },
      ],
      winLine: "Win the week by staying consistent.",
      buttonLabel: "Start My Week",
    },
    Builder: {
      color: "#2FBF71", bg: "#F3FBF6", accent: "#A7E3C2", textSupport: "#2F6B4A", iconName: "builder",
      subtext: "This week, we build.",
      targets: [
        { label: "Training",  value: "3 workouts (4 if time allows)" },
        { label: "Engine",    value: "90 min baseline — build toward 120" },
        { label: "Nutrition", value: "Protein in most meals" },
        { label: "Recovery",  value: "4+ nights of 7+ hours · 2–3 recovery actions" },
      ],
      tightTargets: [
        { label: "Training",  value: "2 workouts" },
        { label: "Engine",    value: "45–60 min aerobic work" },
        { label: "Nutrition", value: "Protein in 2 meals" },
        { label: "Recovery",  value: "3 nights of 7+ hours sleep" },
      ],
      moreTargets: [
        { label: "Option A", value: "Add a 4th workout" },
        { label: "Option B", value: "Or extend aerobic work" },
      ],
      winLine: "Win the week by moving something forward.",
      buttonLabel: "Start My Week",
    },
    Performer: {
      color: "#2C4A6E", bg: "#F0F4F8", accent: "#A8BECE", textSupport: "#1E3348", iconName: "performer",
      subtext: "Perform at a high level — and recover well.",
      targets: [
        { label: "Training",       value: "3 workouts (4 if aligned)" },
        { label: "Engine",         value: "90 min baseline — build toward 150+" },
        { label: "Nutrition",      value: "High-quality fueling" },
        { label: "Recovery",       value: "5+ nights of 7+ hours · 3+ recovery actions" },
        { label: "Optional Push",  value: "Choose 1 session this week to push intensity" },
      ],
      tightTargets: [
        { label: "Training",  value: "Scale back to Builder targets — 3 workouts" },
        { label: "Engine",    value: "90 min aerobic" },
        { label: "Recovery",  value: "Keep recovery high" },
      ],
      moreTargets: [
        { label: "Option A", value: "Push intensity in 1–2 sessions" },
        { label: "Option B", value: "Or extend duration slightly" },
      ],
      winLine: "Win the week by performing well and recovering well.",
      buttonLabel: "Start My Week",
    },
  };

  // ── Why this week (dynamic, for accordion) ─────────────────────────────────
  const whyLines = {
    Stabilizer: hasMajorDisruption
      ? "Life is heavy right now. Protecting your habits during demanding weeks is how you avoid starting over."
      : recoverySignal < 2.5
      ? "Recovery signals were lower this week. Holding steady is the smart play — not a step back."
      : "Your check-in signals suggest a lighter week. Staying consistent here protects long-term progress.",
    Builder: consistencyTrend === "up"
      ? "Your recent trend is moving in the right direction. This is a good week to build on that momentum."
      : "Your signals look solid. Controlled progress this week compounds into real capacity over time.",
    Performer: recoverySignal >= 4
      ? "Your recovery signals are strong and consistency is high. Your body is ready for a higher-output week."
      : "Signals across the board support a bigger week. Train hard — and match it with recovery.",
  };

  // ── This week's focus (pulled from weakest driver signal) ─────────────────
  const protein  = { "Rarely": 0, "Some days": 1, "Most days": 2, "Yes (most days)": 3, "Yes": 3 }[latest.protein ?? latest.proteinFloor] ?? 0;
  const zone2Val = { "0-30": 0, "30-60": 1, "60-90": 2, "90+": 3 }[latest.zone2] ?? 0;
  const sleepOpp = { "Rarely": 0, "1-2 nights": 1, "3-4 nights": 2, "5+ nights": 3 }[latest.sleepOpportunity] ?? 0;
  const reg      = { "None": 0, "1-2 times": 1, "3+ times": 2 }[latest.downshift ?? latest.regulation] ?? 0;
  const focusOptions = [
    { key: "sleep",    score: sleep / 5,      label: "Sleep consistency" },
    { key: "aerobic",  score: zone2Val / 3,   label: "Aerobic volume" },
    { key: "protein",  score: protein / 3,    label: "Protein consistency" },
    { key: "recovery", score: recovery / 5,   label: "Recovery quality" },
    { key: "reg",      score: reg / 2,        label: "Recovery actions" },
    { key: "sleepOpp", score: sleepOpp / 3,   label: "Sleep opportunity" },
  ].sort((a, b) => a.score - b.score);
  const focusSignal = focusOptions[0].label;

  const cfg = ROLE_CONFIG[role];
  return {
    role,
    weekCount,
    reasonLine: reasonLines[role],
    whyLine: whyLines[role],
    focusSignal,
    ...cfg,
  };
}

// ─── Capacity Role (based on latest weekly habit score) ──────────────────────
function getCapacityRole(latestScore) {
  if (latestScore === null || latestScore === undefined) return null;
  if (latestScore >= 85) return { role: "Performer", color: "#1a7a00", emoji: "🔥", icon: "performer",  desc: "Performs at a high level without burning out." };
  if (latestScore >= 70) return { role: "Builder",   color: G,         emoji: "📈", icon: "builder",    desc: "Builds capacity week to week." };
  if (latestScore >= 55) return { role: "Stabilizer",color: "#e09020", emoji: "🛡️", icon: "stabilizer", desc: "Stays consistent when life gets busy." };
  return { role: "Reset", color: "#e05030", emoji: "🔄", icon: null, desc: "Reestablish the basics and bounce back." };
}

// ─── Week Status (based on latest weekly habit score) ─────────────────────────
function getWeekStatus(latestScore) {
  if (latestScore === null || latestScore === undefined) return null;
  if (latestScore >= 85) return { status: "Full Capacity Week", emoji: "🔥", icon: "flame",   color: "#1a7a00", msg: "You're building momentum." };
  if (latestScore >= 55) return { status: "Minimum Effective Week", emoji: "✅", icon: "check",   color: G,         msg: "You stayed consistent during a busy week." };
  return                        { status: "Reset Week",             emoji: "🔁", icon: "refresh", color: "#e05030", msg: "Start simple and re-establish your baseline." };
}

function calcCapacityIndex(vo2Score, gripScore, habitScore) {
  if (isNaN(vo2Score) || isNaN(gripScore) || isNaN(habitScore) ||
      vo2Score == null || gripScore == null || habitScore == null) return null;
  return Math.round(vo2Score * 0.4 + gripScore * 0.4 + habitScore * 0.2);
}

function getCapacityTier(score) {
  if (score >= 85) return { tier: "Peak Capacity",       color: "#1a7a00", emoji: "🏆", icon: "peak", badgeIcon: "trophy" };
  if (score >= 70) return { tier: "Durable Capacity",    color: G,         emoji: "💪", icon: "durable" };
  if (score >= 55) return { tier: "Building Capacity",   color: "#4a9e38", emoji: "📈", icon: "building" };
  if (score >= 40) return { tier: "Emerging Capacity",   color: "#8ab85a", emoji: "🌱", icon: "emerging" };
  return               { tier: "Foundation Capacity", color: "#b0c090", emoji: "🔧", icon: "foundation" };
}

// ─── Weekly Check Score Calculator ────────────────────────────────────────────
// Scoring: Workouts/18 · Zone2/26 · Strength/12 · Movement/12 · Protein/14 · Downshift/8 · SleepOpportunity/12
// Consistency Multiplier: if workouts < 2, total capped at 65
function calcWeeklyScore(check) {
  let score = 0;
  const workoutMap = { "0": 0, "1": 6, "2": 11, "3": 15, "4+": 18 };
  score += workoutMap[check.workouts] || 0;
  score += check.zone2 === "90+" ? 26 : check.zone2 === "60-90" ? 18 : check.zone2 === "30-60" ? 11 : check.zone2 === "0-30" ? 4 : 0;
  score += check.strengthRPE === "Yes" ? 12 : 0;
  score += check.dailyMovement === "High" ? 12 : check.dailyMovement === "Moderate" ? 7 : 0;
  score += check.protein === "Yes (most days)" ? 14 : check.protein === "Most days" ? 10 : check.protein === "Some days" ? 5 : 0;
  score += check.downshift === "3+ times" ? 8 : check.downshift === "1-2 times" ? 4 : 0;
  score += check.sleepOpportunity === "5+ nights" ? 10 : check.sleepOpportunity === "3-4 nights" ? 7 : check.sleepOpportunity === "1-2 nights" ? 3 : 0;
  // Consistency Multiplier: cap at 65 if fewer than 2 workouts
  const workoutsNum = { "0": 0, "1": 1, "2": 2, "3": 3, "4+": 4 }[check.workouts] ?? 0;
  if (workoutsNum < 2) score = Math.min(score, 65);
  return Math.min(Math.round(score), 100);
}

// ─── Main App ─────────────────────────────────────────────────────────────────
const COACH_PIN = "12345";

export default function GBSCApp() {
  const [view, setView] = useState("loading"); // loading | member | register | coach | coachPin
  const [memberView, setMemberView] = useState("profile"); // checkin | profile | checkFeedback
  const [members, setMembers] = useState([]);
  const [currentMember, setCurrentMember] = useState(null);
  const [pinInput, setPinInput] = useState("");
  const [pinError, setPinError] = useState(false);
  const [splashFading, setSplashFading] = useState(false);
  const [pods, setPods] = useState([]);

  useEffect(() => { init(); }, []);

  async function init() {
    const MIN_SPLASH_MS = 2200; // minimum time logo is visible
    const startTime = Date.now();

    // Load pods
    loadPods().then(p => setPods(p));

    let nextView = "register";
    try {
      const memberId = localStorage.getItem("gbsc-this-member");
      if (memberId) {
        const { data, error } = await supabase.from("members").select("data").eq("id", memberId).single();
        if (!error && data) {
          const member = data.data;
          setCurrentMember(member);
          nextView = "member";

          // Determine the correct starting sub-view for returning members
          const nonBaseline = (member.weeklyChecks || []).filter(c => c && !c.isBaseline);
          const lastCheck = nonBaseline.length > 0
            ? nonBaseline[nonBaseline.length - 1]
            : null;

          if (lastCheck) {
            if (!isEligibleForCheckin(lastCheck.date)) {
              // Already checked in this week (since Monday) — go to feedback
              setMemberView("checkFeedback");
            } else if (nonBaseline.length >= 8) {
              // Program complete
              setMemberView("checkFeedback");
            } else {
              // A full week has passed — eligible for next check-in
              setMemberView("checkin");
            }
          } else {
            // Has baseline but no weekly checks yet — show check-in
            setMemberView("checkin");
          }
        }
      }
    } catch {}

    // Wait for minimum splash time, then fade out over 600ms before switching view
    const elapsed = Date.now() - startTime;
    const remaining = Math.max(0, MIN_SPLASH_MS - elapsed);
    await new Promise(r => setTimeout(r, remaining));
    setSplashFading(true);
    await new Promise(r => setTimeout(r, 600));
    setView(nextView);
  }

  async function loadMembers() {
    try {
      const { data, error } = await supabase.from("members").select("id, data");
      if (!error && data) {
        setMembers(data.filter(row => row.id !== "__pods__").map(row => row.data));
      }
    } catch {}
  }

  async function saveMember(m) {
    try {
      await supabase.from("members").upsert({ id: m.id, data: m, updated_at: new Date().toISOString() });
      localStorage.setItem("gbsc-this-member", m.id);
    } catch (e) { console.error(e); }
    setCurrentMember(m);
    setMembers(prev => {
      const idx = prev.findIndex(x => x.id === m.id);
      if (idx >= 0) { const n = [...prev]; n[idx] = m; return n; }
      return [...prev, m];
    });
  }

  // ── LOADING ───────────────────────────────────────────────────────────────
  if (view === "loading") {
    return (
      <div style={{
        minHeight: "100vh", background: DARK,
        display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: "2.5rem",
        opacity: splashFading ? 0 : 1,
        transition: splashFading ? "opacity 0.6s ease" : "none",
      }}>
        <div style={{
          background: "#fff",
          borderRadius: "24px",
          padding: "2rem 2.8rem",
          boxShadow: "0 8px 40px rgba(0,0,0,0.45), 0 2px 12px rgba(0,0,0,0.3)",
          opacity: splashFading ? 0 : 1,
          transform: splashFading ? "scale(0.97)" : "scale(1)",
          transition: "opacity 0.6s ease, transform 0.6s ease",
        }}>
          <img
            src={LOGO_HORIZ} alt="GBSC"
            style={{ width: "min(280px, 65vw)", display: "block" }}
          />
        </div>
        <div style={{
          width: "44px", height: "44px",
          border: `3px solid rgba(255,255,255,0.12)`,
          borderTop: `3px solid ${G}`,
          borderRadius: "50%",
          animation: "spin 1.1s linear infinite",
          opacity: splashFading ? 0 : 0.85,
          transition: "opacity 0.3s ease",
        }} />
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  // ── COACH PIN ─────────────────────────────────────────────────────────────
  if (view === "coachPin") {
    return (
      <div style={{ minHeight: "100vh", background: PAGE_BG, fontFamily: "'Georgia', serif", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "2rem" }}>
        <img src={LOGO_HORIZ} alt="GBSC" style={{ width: "min(280px, 80vw)", marginBottom: "2rem" }} />
        <div style={{ background: DARK, borderRadius: "16px", padding: "2rem", width: "100%", maxWidth: "320px" }}>
          <div style={{ color: "#fff", fontWeight: "bold", fontSize: "1.1rem", marginBottom: "1.2rem", textAlign: "center" }}>🔒 Coach Access</div>
          <input
            type="password"
            placeholder="Enter PIN"
            value={pinInput}
            onChange={e => { setPinInput(e.target.value); setPinError(false); }}
            onKeyDown={e => { if (e.key === "Enter") checkPin(); }}
            style={{ width: "100%", padding: "0.8rem 1rem", borderRadius: "8px", border: pinError ? "2px solid #e74c3c" : "2px solid #555", fontSize: "1.2rem", textAlign: "center", letterSpacing: "0.3em", boxSizing: "border-box", marginBottom: "0.5rem" }}
          />
          {pinError && <div style={{ color: "#e74c3c", fontSize: "0.85rem", textAlign: "center", marginBottom: "0.5rem" }}>Incorrect PIN</div>}
          <button onClick={checkPin}
            style={{ width: "100%", background: G, color: "#fff", border: "none", borderRadius: "10px", padding: "0.9rem", fontSize: "1rem", fontWeight: "bold", cursor: "pointer", marginTop: "0.3rem" }}>
            Unlock →
          </button>
          <button onClick={() => { setPinInput(""); setPinError(false); setView(currentMember ? "member" : "register"); }}
            style={{ width: "100%", background: "none", border: "none", color: "#aaa", cursor: "pointer", marginTop: "0.8rem", fontSize: "0.9rem" }}>
            ← Back
          </button>
        </div>
      </div>
    );
  }

  function checkPin() {
    if (pinInput === COACH_PIN) {
      setPinInput("");
      setPinError(false);
      loadMembers().then(() => setView("coach"));
    } else {
      setPinError(true);
    }
  }

  // ── REGISTRATION (first-time only) ────────────────────────────────────────
  if (view === "register") {
    return (
      <MemberPortal
        view="onboard"
        setView={setMemberView}
        members={members}
        currentMember={currentMember}
        setCurrentMember={setCurrentMember}
        saveMember={saveMember}
        pods={pods}
        setPods={setPods}
        onRegistered={() => setView("member")}
        onCoachAccess={() => setView("coachPin")}
      />
    );
  }

  // ── RETURNING MEMBER ──────────────────────────────────────────────────────
  if (view === "member") {
    return (
      <MemberPortal
        view={memberView}
        setView={setMemberView}
        members={members}
        currentMember={currentMember}
        setCurrentMember={setCurrentMember}
        saveMember={saveMember}
        pods={pods}
        setPods={setPods}
        onRegistered={() => setView("member")}
        onCoachAccess={() => setView("coachPin")}
      />
    );
  }

  // ── COACH DASHBOARD ───────────────────────────────────────────────────────
  return (
    <CoachDashboard
      members={members}
      loadMembers={loadMembers}
      pods={pods}
      setPods={setPods}
      onBack={() => setView(currentMember ? "member" : "register")}
    />
  );
}

// ─── SHARED UI COMPONENTS (must be at module scope to avoid re-mount on re-render) ───
function F({ label, children }) {
  return (
    <div style={{ marginBottom: "1.2rem" }}>
      <label style={{ display: "block", fontWeight: "bold", marginBottom: "0.3rem", color: DARK, fontSize: "0.9rem" }}>{label}</label>
      {children}
    </div>
  );
}
function RadioGroup({ options, value, onChange }) {
  return (
    <div style={{ display: "flex", flexWrap: "wrap", gap: "0.5rem" }}>
      {options.map(opt => (
        <button key={opt} onClick={() => onChange(opt)}
          style={{ padding: "0.5rem 1rem", minHeight: "44px", border: `2px solid ${value === opt ? G : "#ddd"}`, borderRadius: "8px", background: value === opt ? G : "#fff", color: value === opt ? "#fff" : DARK, cursor: "pointer", fontSize: "0.9rem", fontWeight: value === opt ? "bold" : "normal", display: "flex", alignItems: "center" }}>
          {opt}
        </button>
      ))}
    </div>
  );
}

function ScaleGroup({ value, onChange, field, setCheck, labels }) {
  const resolvedValue = value !== undefined ? value : undefined;
  const handleClick = (n) => {
    if (onChange) onChange(String(n));
    else if (field && setCheck) setCheck(c => ({...c, [field]: String(n)}));
  };
  const selectedLabel = resolvedValue && labels ? labels[parseInt(resolvedValue) - 1] : null;
  return (
    <div>
      <div style={{ display: "flex", gap: "0.4rem", marginBottom: "0.3rem" }}>
        {[1,2,3,4,5].map(n => (
          <button key={n} onClick={() => handleClick(n)}
            style={{ flex: 1, height: "44px", border: `2px solid ${String(n) === resolvedValue ? G : "#ddd"}`, borderRadius: "8px", background: String(n) === resolvedValue ? G : "#fff", color: String(n) === resolvedValue ? "#fff" : DARK, cursor: "pointer", fontWeight: "bold", fontSize: "1rem" }}>
            {n}
          </button>
        ))}
      </div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", fontSize: "0.7rem", marginTop: "0.2rem" }}>
        {labels && <span style={{ color: "#bbb" }}>{labels[0]}</span>}
        {selectedLabel && <span style={{ color: G, fontWeight: "bold", fontSize: "0.78rem" }}>✓ {selectedLabel}</span>}
        {labels && <span style={{ color: "#bbb" }}>{labels[4]}</span>}
      </div>
    </div>
  );
}

