// ─── COACH DASHBOARD ─────────────────────────────────────────────────────────
function CoachDashboard({ members, loadMembers, pods, setPods, onBack }) {
  const [selected, setSelected] = useState(null);
  const [search, setSearch] = useState("");
  const [refreshing, setRefreshing] = useState(false);
  const [downloading, setDownloading] = useState(false);
  const [confirmWipeAll, setConfirmWipeAll] = useState(false);
  const [coachTab, setCoachTab] = useState("members"); // "members" | "pods"
  const [editingPod, setEditingPod] = useState(null); // pod id or "new"
  const [podSaving, setPodSaving] = useState(false);
  const [podDraft, setPodDraft] = useState(null); // { id, name, emoji, memberIds }

  async function handleRefresh() {
    setRefreshing(true);
    await loadMembers();
    setTimeout(() => setRefreshing(false), 600);
  }

  async function deleteMember(member) {
    if (!window.confirm(`Delete ${member.name}? This cannot be undone.`)) return;
    try {
      await supabase.from("members").delete().eq("id", member.id);
    } catch {}
    await loadMembers();
    setSelected(null);
  }

  async function deleteAllMembers() {
    try {
      await supabase.from("members").delete().neq("id", "___never___");
    } catch {}
    await loadMembers();
    setConfirmWipeAll(false);
  }

  async function handleSavePod() {
    if (!podDraft || !podDraft.name.trim()) return;
    setPodSaving(true);
    let updatedPods;
    if (podDraft.id === "new") {
      const newPod = { ...podDraft, id: "pod_" + Date.now() };
      updatedPods = [...pods, newPod];
    } else {
      updatedPods = pods.map(p => p.id === podDraft.id ? podDraft : p);
    }
    await savePods(updatedPods);
    setPods(updatedPods);
    setEditingPod(null);
    setPodDraft(null);
    setPodSaving(false);
  }

  async function handleDeletePod(podId) {
    if (!window.confirm("Delete this pod?")) return;
    const updatedPods = pods.filter(p => p.id !== podId);
    await savePods(updatedPods);
    setPods(updatedPods);
  }

  function startNewPod() {
    // Pick a name not already used
    const usedNames = pods.map(p => p.name);
    const available = POD_NAMES.filter(n => !usedNames.includes(n.name));
    const pick = available.length > 0
      ? available[Math.floor(Math.random() * available.length)]
      : { name: `Pod ${pods.length + 1}`, emoji: "🏋" };
    setPodDraft({ id: "new", name: pick.name, emoji: pick.emoji, memberIds: [], captainId: null });
    setEditingPod("new");
  }

  function startEditPod(pod) {
    setPodDraft({ ...pod, memberIds: [...(pod.memberIds || [])], captainId: pod.captainId || null });
    setEditingPod(pod.id);
  }

  function downloadCSV() {
    setDownloading(true);
    const headers = [
      "member_id","name","email","age","sex","weight_lbs","enrolled_date",
      "vo2_pre","vo2_score","grip_pre_lbs","grip_score",
      "week","date","is_baseline","habit_score",
      "workouts","zone2_minutes","strength_rpe","daily_movement","protein","sleep_opportunity","downshift",
      "sleep_quality","energy_level","physical_recovery","disruption",
      "capacity_index","tier"
    ];

    const rows = [];
    for (const m of members) {
      const allChecks = m.weeklyChecks || [];
      const checks = allChecks.filter(c => c && !c.isBaseline);
      if (allChecks.length === 0) {
        rows.push([
          m.id, m.name, m.email, m.age, m.sex, m.weight,
          m.enrolledDate, m.vo2_pre, m.vo2Score_pre, m.grip_pre, m.gripScore_pre,
          "","","","","","","","","","","","","","","",""
        ]);
      } else {
        const habitAvg = checks.length ? Math.round(checks.reduce((s,c) => s+c.score, 0) / checks.length) : 0;
        const ci = calcCapacityIndex(m.vo2Score_pre, m.gripScore_pre, habitAvg);
        const tier = getCapacityTier(ci);
        for (const c of allChecks) {
          rows.push([
            m.id, m.name, m.email, m.age, m.sex, m.weight,
            m.enrolledDate, m.vo2_pre, m.vo2Score_pre, m.grip_pre, m.gripScore_pre,
            c.week ?? 0, c.date, c.isBaseline ? "YES" : "NO", c.score,
            c.workouts, c.zone2 ?? "", c.strengthRPE, c.dailyMovement ?? "", c.protein ?? "", c.sleepOpportunity ?? "", c.downshift ?? "",
            c.sleepQuality, c.energyLevel, c.physicalRecovery, c.disruption ?? "",
            ci, tier.tier
          ]);
        }
      }
    }

    const escape = v => {
      const s = v === undefined || v === null ? "" : String(v);
      return s.includes(",") || s.includes('"') || s.includes("\n") ? `"${s.replace(/"/g,'""')}"` : s;
    };
    const csv = [headers, ...rows].map(r => r.map(escape).join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    const today = localDateStr();
    a.download = `gbsc-capacity-data-${today}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    setTimeout(() => setDownloading(false), 800);
  }

  function downloadJSON() {
    const today = localDateStr();
    const payload = {
      exported: new Date().toISOString(),
      memberCount: members.length,
      members: members.map(m => {
        const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
        const habitAvg = checks.length ? Math.round(checks.reduce((s,c) => s+c.score, 0) / checks.length) : null;
        const ci = habitAvg !== null ? calcCapacityIndex(m.vo2Score_pre, m.gripScore_pre, habitAvg) : null;
        const tier = ci !== null ? getCapacityTier(ci) : null;
        return { ...m, capacityIndex: ci, tier: tier?.tier ?? null };
      })
    };
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `gbsc-capacity-data-${today}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }

  const filtered = members.filter(m => m.name?.toLowerCase().includes(search.toLowerCase()) || m.email?.toLowerCase().includes(search.toLowerCase()));

  // Gym-wide averages
  const withCI = members.filter(m => (m.weeklyChecks || []).filter(c => c && !c.isBaseline).length > 0);
  const avgCI = withCI.length ? Math.round(withCI.reduce((s, m) => {
    const nonBase = m.weeklyChecks.filter(c => c && !c.isBaseline);
    const habit = Math.round(nonBase.reduce((a,c) => a+c.score,0)/nonBase.length);
    return s + calcCapacityIndex(m.vo2Score_pre, m.gripScore_pre, habit);
  }, 0) / withCI.length) : null;

  const hdr = (
    <div style={{ background: DARK }}>
      <div style={{ padding: "1rem 1.5rem", display: "flex", alignItems: "center", gap: "1rem" }}>
        <button onClick={onBack} style={{ background: "none", border: "none", color: "#fff", cursor: "pointer", fontSize: "1.2rem" }}>←</button>
        <img src={LOGO_ICON} alt="GBSC" style={{ height: "36px", borderRadius: "4px" }} />
        <div style={{ color: "#fff", fontWeight: "bold", letterSpacing: "0.05em", flex: 1 }}>Coach Dashboard</div>
        <button onClick={handleRefresh} style={{ background: "none", border: "none", color: G, cursor: "pointer", fontSize: "0.85rem" }}>
          {refreshing ? "..." : "↻ Refresh"}
        </button>
      </div>
      <div style={{ display: "flex", borderTop: "1px solid #3a3a3a", padding: "0 1.5rem" }}>
        {[["members", "Members"], ["insights", "Insights"], ["analytics", "Analytics"], ["pods", "Pods"]].map(([tab, label]) => (
          <button key={tab} onClick={() => { setCoachTab(tab); setSelected(null); setEditingPod(null); setPodDraft(null); }}
            style={{ background: "none", border: "none", color: coachTab === tab ? G : "#aaa",
              borderBottom: coachTab === tab ? `2.5px solid ${G}` : "2.5px solid transparent",
              padding: "0.6rem 1.2rem", cursor: "pointer", fontWeight: coachTab === tab ? "bold" : "normal",
              fontSize: "0.88rem", transition: "color 0.2s" }}>
            {label}
          </button>
        ))}
      </div>
    </div>
  );

  if (selected) {
    const allSelectedChecks = selected.weeklyChecks || [];
    const checks = allSelectedChecks.filter(c => c && !c.isBaseline);
    const habitAvg = checks.length ? Math.round(checks.reduce((s,c) => s+c.score,0)/checks.length) : null;
    const ci = habitAvg !== null ? calcCapacityIndex(selected.vo2Score_pre, selected.gripScore_pre, habitAvg) : null;
    const tier = ci !== null ? getCapacityTier(ci) : null;
    return (
      <div style={{ minHeight: "100vh", background: PAGE_BG, fontFamily: "Georgia, serif" }}>
        {hdr}
        <div style={{ maxWidth: "600px", margin: "0 auto", padding: "1.5rem" }}>
          <button onClick={() => setSelected(null)} style={{ background: "none", border: "none", color: G, cursor: "pointer", marginBottom: "1rem", fontWeight: "bold" }}>← All Members</button>
          <div style={{ background: DARK, borderRadius: "16px", padding: "1.5rem", color: "#fff", marginBottom: "1.5rem" }}>
            <div style={{ fontSize: "1.3rem", fontWeight: "bold" }}>{selected.name}</div>
            <div style={{ color: "#aaa", fontSize: "0.85rem" }}>{selected.email} · Age {selected.age} · {selected.sex}</div>
            <div style={{ color: "#aaa", fontSize: "0.85rem" }}>Enrolled: {selected.enrolledDate}</div>
            {ci !== null && (
              <div style={{ marginTop: "1rem", display: "flex", alignItems: "center", gap: "1rem" }}>
                <div style={{ fontSize: "2.5rem", fontWeight: "bold", color: G }}>{ci}</div>
                <div>
                  <div style={{ color: tier.color, fontWeight: "bold", display:"flex", alignItems:"center", gap:"0.3rem" }}><GBSCIcon name={tier.icon} size={14} color={tier.color} strokeWidth={0}/>{tier.tier}</div>
                  <div style={{ color: "#aaa", fontSize: "0.8rem" }}>Week {checks.length} of 8</div>
                </div>
              </div>
            )}
            {ci === null && <div style={{ color: "#aaa", marginTop: "0.5rem", fontSize: "0.9rem" }}>No check-ins yet</div>}
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "0.8rem", marginBottom: "1.5rem" }}>
            {[
              { label: "VO₂ Pre", val: selected.vo2_pre, sub: `Score: ${selected.vo2Score_pre}` },
              { label: "Grip Pre (lbs)", val: selected.grip_pre, sub: `Score: ${selected.gripScore_pre}` },
              { label: "Habit Avg", val: habitAvg ?? "—", sub: "of 100" },
            ].map(({ label, val, sub }) => (
              <div key={label} style={{ background: CARD, borderRadius: "12px", padding: "1rem", textAlign: "center" }}>
                <div style={{ fontSize: "1.4rem", fontWeight: "bold", color: G }}>{val}</div>
                <div style={{ fontSize: "0.75rem", color: "#666" }}>{label}</div>
                <div style={{ fontSize: "0.7rem", color: "#aaa" }}>{sub}</div>
              </div>
            ))}
          </div>
          {allSelectedChecks.length > 0 && (
            <div>
              <div style={{ fontWeight: "bold", marginBottom: "0.8rem", color: DARK }}>Weekly Check-In Log</div>
              <div style={{ overflowX: "auto" }}>
                <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.85rem" }}>
                  <thead>
                    <tr style={{ background: DARK, color: "#fff" }}>
                      {["Week","Date","Score","Workouts","Strength","Movement","Zone 2","Protein","Sleep Opp","Downshift","Sleep","Energy","Recovery","Disruption"].map(h => (
                        <th key={h} style={{ padding: "0.5rem 0.7rem", textAlign: "left", fontWeight: "normal", whiteSpace: "nowrap" }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {allSelectedChecks.map((c, i) => (
                      <tr key={i} style={{ background: i % 2 ? CARD : "#fff" }}>
                        <td style={{ padding: "0.5rem 0.7rem", fontWeight: "bold", color: G }}>{c.isBaseline ? "Base" : c.week}</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.date}</td>
                        <td style={{ padding: "0.5rem 0.7rem", fontWeight: "bold" }}>{c.score}</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.workouts}</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.strengthRPE}</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.dailyMovement ?? "—"}</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.zone2 ?? "—"}</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.protein ?? "—"}</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.sleepOpportunity ?? "—"}</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.downshift ?? "—"}</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.sleepQuality}/5</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.energyLevel}/5</td>
                        <td style={{ padding: "0.5rem 0.7rem" }}>{c.physicalRecovery}/5</td>
                        <td style={{ padding: "0.5rem 0.7rem", color: c.disruption === "Major disruption" ? "#c07030" : c.disruption === "Some disruption" ? "#b09020" : "#aaa" }}>
                          {c.disruption === "Major disruption" ? "🌊 Major" : c.disruption === "Some disruption" ? "〰️ Some" : "—"}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Delete member */}
          <div style={{ marginTop: "2rem", paddingTop: "1.5rem", borderTop: "1px solid #eee" }}>
            <button onClick={() => deleteMember(selected)}
              style={{ width: "100%", background: "none", border: "2px solid #e74c3c", color: "#e74c3c", borderRadius: "12px", padding: "0.8rem", fontSize: "0.95rem", fontWeight: "bold", cursor: "pointer" }}>
              🗑 Delete {selected.name}'s Profile
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ── INSIGHTS TAB ─────────────────────────────────────────────────────────
  if (coachTab === "insights") {
    const activeMembers = members.filter(m => (m.weeklyChecks || []).filter(c => c && !c.isBaseline).length >= 2);

    // ── Trending down: last 2 non-baseline scores declining
    const trendingDown = activeMembers
      .map(m => {
        const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
        const last = checks[checks.length - 1];
        const prev = checks[checks.length - 2];
        const drop = prev.score - last.score;
        return { m, last, prev, drop };
      })
      .filter(({ drop }) => drop > 0)
      .sort((a, b) => b.drop - a.drop);

    // ── Low recovery: latest check physicalRecovery <= 2
    const lowRecovery = members
      .map(m => {
        const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
        if (!checks.length) return null;
        const last = checks[checks.length - 1];
        const rec = parseInt(last.physicalRecovery) || 0;
        const sleep = parseInt(last.sleepQuality) || 0;
        const energy = parseInt(last.energyLevel) || 0;
        return rec <= 2 ? { m, last, rec, sleep, energy } : null;
      })
      .filter(Boolean)
      .sort((a, b) => a.rec - b.rec);

    // ── Pod engagement: pods with < 50% checked in this week
    const podEngagement = pods.map(pod => {
      const podMembers = members.filter(m => pod.memberIds.includes(m.id));
      const checkedIn = podMembers.filter(m => {
        const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
        if (!checks.length) return false;
        const last = checks[checks.length - 1];
        return last.date && !isEligibleForCheckin(last.date);
      });
      return { pod, podMembers, checkedIn, pct: podMembers.length ? Math.round((checkedIn.length / podMembers.length) * 100) : 0 };
    }).sort((a, b) => a.pct - b.pct);

    const SectionHeader = ({ emoji, title, count, color, unit = "member" }) => (
      <div style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: "0.9rem" }}>
        <span style={{ fontSize: "1.2rem" }}>{emoji}</span>
        <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.95rem", flex: 1 }}>{title}</div>
        <div style={{ background: color + "22", border: `1px solid ${color}55`, borderRadius: "999px",
          padding: "0.15rem 0.6rem", fontSize: "0.72rem", fontWeight: "bold", color: color }}>
          {count} {unit}{count !== 1 ? "s" : ""}
        </div>
      </div>
    );

    return (
      <div style={{ minHeight: "100vh", background: PAGE_BG, fontFamily: "Georgia, serif" }}>
        {hdr}
        <div style={{ maxWidth: "700px", margin: "0 auto", padding: "1.5rem" }}>

          {/* ── Trending Down ──────────────────────────────────────────────── */}
          <div style={{ background: CARD, borderRadius: "16px", padding: "1.3rem 1.4rem", marginBottom: "1.2rem" }}>
            <SectionHeader emoji="📉" title="Trending Down" count={trendingDown.length} color="#e07030" />
            {trendingDown.length === 0 ? (
              <div style={{ color: "#aaa", fontSize: "0.85rem", textAlign: "center", padding: "1rem 0" }}>No members trending down this week 🎉</div>
            ) : (
              trendingDown.map(({ m, last, prev, drop }) => (
                <div key={m.id} onClick={() => setSelected(m)}
                  style={{ display: "flex", alignItems: "center", gap: "0.9rem", padding: "0.75rem 0.9rem",
                    borderRadius: "10px", marginBottom: "0.4rem", cursor: "pointer", background: "#fff8f5",
                    border: "1px solid #fad0b8", transition: "background 0.15s" }}
                  onMouseEnter={e => e.currentTarget.style.background = "#ffeee4"}
                  onMouseLeave={e => e.currentTarget.style.background = "#fff8f5"}>
                  <div style={{ width: "36px", height: "36px", borderRadius: "50%", flexShrink: 0,
                    background: `hsl(${(m.name.charCodeAt(0) * 37) % 360}, 55%, 55%)`,
                    color: "#fff", fontWeight: "bold", fontSize: "0.85rem",
                    display: "flex", alignItems: "center", justifyContent: "center" }}>
                    {m.name.charAt(0).toUpperCase()}
                  </div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.9rem" }}>{m.name}</div>
                    <div style={{ fontSize: "0.75rem", color: "#888" }}>
                      Week {prev.week} → Week {last.week}
                    </div>
                  </div>
                  <div style={{ textAlign: "right" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: "0.4rem", justifyContent: "flex-end" }}>
                      <span style={{ fontSize: "0.85rem", color: "#aaa" }}>{prev.score}</span>
                      <span style={{ color: "#e07030", fontSize: "0.85rem" }}>→</span>
                      <span style={{ fontWeight: "bold", fontSize: "1rem", color: "#e07030" }}>{last.score}</span>
                    </div>
                    <div style={{ fontSize: "0.72rem", color: "#e07030", fontWeight: "bold" }}>▼ {drop} pts</div>
                  </div>
                </div>
              ))
            )}
          </div>

          {/* ── Low Recovery ───────────────────────────────────────────────── */}
          <div style={{ background: CARD, borderRadius: "16px", padding: "1.3rem 1.4rem", marginBottom: "1.2rem" }}>
            <SectionHeader emoji="🔴" title="Low Recovery Scores" count={lowRecovery.length} color="#c0303a" />
            {lowRecovery.length === 0 ? (
              <div style={{ color: "#aaa", fontSize: "0.85rem", textAlign: "center", padding: "1rem 0" }}>Everyone's recovering well this week ✓</div>
            ) : (
              lowRecovery.map(({ m, last, rec, sleep, energy }) => {
                const recLabels = ["—", "Beat Up", "Tight", "Normal", "Recovered", "Fresh"];
                const sleepLabels = ["—", "Poor", "Inconsistent", "Adequate", "Good", "Excellent"];
                const energyLabels = ["—", "Drained", "Low", "Stable", "Strong", "High & Steady"];
                const dotColor = (val) => val <= 2 ? "#e74c3c" : val <= 3 ? "#e09020" : G;
                return (
                  <div key={m.id} onClick={() => setSelected(m)}
                    style={{ display: "flex", alignItems: "center", gap: "0.9rem", padding: "0.75rem 0.9rem",
                      borderRadius: "10px", marginBottom: "0.4rem", cursor: "pointer", background: "#fff5f5",
                      border: "1px solid #f5c0c0", transition: "background 0.15s" }}
                    onMouseEnter={e => e.currentTarget.style.background = "#ffe8e8"}
                    onMouseLeave={e => e.currentTarget.style.background = "#fff5f5"}>
                    <div style={{ width: "36px", height: "36px", borderRadius: "50%", flexShrink: 0,
                      background: `hsl(${(m.name.charCodeAt(0) * 37) % 360}, 55%, 55%)`,
                      color: "#fff", fontWeight: "bold", fontSize: "0.85rem",
                      display: "flex", alignItems: "center", justifyContent: "center" }}>
                      {m.name.charAt(0).toUpperCase()}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.9rem" }}>{m.name}</div>
                      <div style={{ fontSize: "0.72rem", color: "#888" }}>Week {last.week} · {last.disruption && last.disruption !== "None" ? `⚠ ${last.disruption}` : "No disruption logged"}</div>
                    </div>
                    <div style={{ display: "flex", gap: "0.5rem" }}>
                      {[
                        { icon: "🔄", val: rec, label: recLabels[rec] },
                        { icon: "😴", val: sleep, label: sleepLabels[sleep] },
                        { icon: "⚡", val: energy, label: energyLabels[energy] },
                      ].map(({ icon, val, label }) => (
                        <div key={icon} style={{ textAlign: "center", minWidth: "42px" }}>
                          <div style={{ fontSize: "0.75rem" }}>{icon}</div>
                          <div style={{ fontSize: "0.82rem", fontWeight: "bold", color: dotColor(val) }}>{val}/5</div>
                          <div style={{ fontSize: "0.58rem", color: "#aaa", lineHeight: 1.2 }}>{label}</div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })
            )}
          </div>

          {/* ── Pod Engagement ─────────────────────────────────────────────── */}
          <div style={{ background: CARD, borderRadius: "16px", padding: "1.3rem 1.4rem", marginBottom: "1.2rem" }}>
            <SectionHeader emoji="🫛" title="Pod Engagement This Week" count={pods.length} color="#7a60c0" unit="pod" />
            {pods.length === 0 ? (
              <div style={{ color: "#aaa", fontSize: "0.85rem", textAlign: "center", padding: "1rem 0" }}>No pods created yet</div>
            ) : (
              podEngagement.map(({ pod, podMembers, checkedIn, pct }) => {
                const barColor = pct >= 80 ? G : pct >= 50 ? "#e09020" : "#e74c3c";
                const captain = pod.captainId ? members.find(m => m.id === pod.captainId) : null;
                return (
                  <div key={pod.id} style={{ marginBottom: "1rem", paddingBottom: "1rem",
                    borderBottom: "1px solid #f0f0f0" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: "0.5rem", marginBottom: "0.5rem" }}>
                      <span style={{ fontSize: "1.2rem" }}>{pod.emoji}</span>
                      <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.9rem", flex: 1 }}>{pod.name}</div>
                      {captain && <div style={{ fontSize: "0.72rem", color: "#f0a500" }}>⭐ {captain.name}</div>}
                      <div style={{ fontSize: "0.82rem", fontWeight: "bold", color: barColor }}>
                        {checkedIn.length}/{podMembers.length}
                      </div>
                    </div>
                    {/* Progress bar */}
                    <div style={{ background: "#eee", borderRadius: "999px", height: "8px", marginBottom: "0.5rem", overflow: "hidden" }}>
                      <div style={{ background: barColor, width: `${pct}%`, height: "100%", borderRadius: "999px", transition: "width 0.4s ease" }} />
                    </div>
                    {/* Member chips */}
                    <div style={{ display: "flex", flexWrap: "wrap", gap: "0.4rem" }}>
                      {podMembers.map(m => {
                        const didCheck = checkedIn.find(c => c.id === m.id);
                        return (
                          <div key={m.id} onClick={() => setSelected(m)}
                            style={{ display: "flex", alignItems: "center", gap: "0.35rem",
                              background: didCheck ? `${G}15` : "#fff0f0",
                              border: `1px solid ${didCheck ? G + "55" : "#f5c0c0"}`,
                              borderRadius: "999px", padding: "0.2rem 0.6rem",
                              fontSize: "0.75rem", cursor: "pointer" }}>
                            <span style={{ fontSize: "0.7rem" }}>{didCheck ? "✓" : "○"}</span>
                            <span style={{ color: DARK, fontWeight: didCheck ? "bold" : "normal" }}>{m.name}</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })
            )}
          </div>

        </div>
      </div>
    );
  }

  // ── ANALYTICS TAB ────────────────────────────────────────────────────────
  if (coachTab === "analytics") {

    // ── 1. Top 5 Most Improved (largest CI gain from first to latest check-in)
    const mostImproved = members
      .map(m => {
        const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
        if (checks.length < 2) return null;
        const firstHabit = checks[0].score;
        const latestHabit = Math.round(checks.reduce((s,c) => s+c.score, 0) / checks.length);
        const firstCI  = calcCapacityIndex(m.vo2Score_pre, m.gripScore_pre, firstHabit);
        const latestCI = calcCapacityIndex(m.vo2Score_pre, m.gripScore_pre, latestHabit);
        if (firstCI === null || latestCI === null) return null;
        const gain = latestCI - firstCI;
        return { m, firstCI, latestCI, gain, weekCount: checks.length };
      })
      .filter(Boolean)
      .sort((a, b) => b.gain - a.gain)
      .slice(0, 5);

    // ── 2. Capacity tier distribution
    const tierOrder = [
      { name: "Peak Capacity",       emoji: "🏆", color: "#1a7a00" },
      { name: "Durable Capacity",    emoji: "💪", color: G },
      { name: "Building Capacity",   emoji: "📈", color: "#4a9e38" },
      { name: "Emerging Capacity",   emoji: "🌱", color: "#8ab85a" },
      { name: "Foundation Capacity", emoji: "🔧", color: "#b0c090" },
    ];
    const tierCounts = tierOrder.map(t => ({ ...t, count: 0, members: [] }));
    members.forEach(m => {
      const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
      if (!checks.length) return;
      const habitAvg = Math.round(checks.reduce((s,c) => s+c.score, 0) / checks.length);
      const ci = calcCapacityIndex(m.vo2Score_pre, m.gripScore_pre, habitAvg);
      if (ci === null) return;
      const tier = getCapacityTier(ci);
      const slot = tierCounts.find(t => t.name === tier.tier);
      if (slot) { slot.count++; slot.members.push(m.name); }
    });
    const totalWithCI = tierCounts.reduce((s, t) => s + t.count, 0);

    // ── 3. Community CI trend — avg CI per week across all members
    const weekNums = new Set();
    members.forEach(m => (m.weeklyChecks || []).forEach(c => { if (c && !c.isBaseline) weekNums.add(c.week); }));
    const communityTrend = Array.from(weekNums).sort((a, b) => a - b).map(wk => {
      const cis = [];
      members.forEach(m => {
        const checksUpTo = (m.weeklyChecks || []).filter(c => c && !c.isBaseline && c.week <= wk);
        if (!checksUpTo.length) return;
        const habit = Math.round(checksUpTo.reduce((s,c) => s+c.score, 0) / checksUpTo.length);
        const ci = calcCapacityIndex(m.vo2Score_pre, m.gripScore_pre, habit);
        if (ci !== null) cis.push(ci);
      });
      return { week: wk, avg: cis.length ? Math.round(cis.reduce((a,b) => a+b, 0) / cis.length) : null, count: cis.length };
    }).filter(w => w.avg !== null);

    // ── 4. Captains list (members who are captainId in any pod)
    const captains = pods
      .filter(p => p.captainId)
      .map(p => {
        const m = members.find(mem => mem.id === p.captainId);
        if (!m) return null;
        return { member: m, pod: p };
      })
      .filter(Boolean)
      .sort((a, b) => a.member.name.localeCompare(b.member.name));

    function downloadCaptainsCSV() {
      const headers = ["Name", "Email", "Pod", "Age", "Sex"];
      const rows = captains.map(({ member: m, pod: p }) => [
        m.name, m.email || "", p.name, m.age || "", m.sex || ""
      ]);
      const escape = v => { const s = String(v ?? ""); return s.includes(",") || s.includes('"') ? `"${s.replace(/"/g,'""')}"` : s; };
      const csv = [headers, ...rows].map(r => r.map(escape).join(",")).join("\n");
      const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url; a.download = `gbsc-captains-${localDateStr()}.csv`; a.click();
      URL.revokeObjectURL(url);
    }

    // SVG trend chart helpers
    const trendPoints = communityTrend;
    const chartW = 560, chartH = 120, padL = 36, padR = 16, padT = 12, padB = 28;
    const plotW = chartW - padL - padR;
    const plotH = chartH - padT - padB;
    const allAvgs = trendPoints.map(p => p.avg);
    const minY = allAvgs.length ? Math.max(0, Math.min(...allAvgs) - 8) : 0;
    const maxY = allAvgs.length ? Math.min(100, Math.max(...allAvgs) + 8) : 100;
    const rangeY = maxY - minY || 1;
    const cx = i => padL + (trendPoints.length > 1 ? (i / (trendPoints.length - 1)) * plotW : plotW / 2);
    const cy = v => padT + (1 - (v - minY) / rangeY) * plotH;
    const linePath = trendPoints.map((p, i) => `${i === 0 ? "M" : "L"} ${cx(i).toFixed(1)} ${cy(p.avg).toFixed(1)}`).join(" ");
    const areaPath = trendPoints.length > 1
      ? `${linePath} L ${cx(trendPoints.length-1).toFixed(1)} ${(padT+plotH).toFixed(1)} L ${cx(0).toFixed(1)} ${(padT+plotH).toFixed(1)} Z`
      : "";

    return (
      <div style={{ minHeight: "100vh", background: PAGE_BG, fontFamily: "Georgia, serif" }}>
        {hdr}
        <div style={{ maxWidth: "700px", margin: "0 auto", padding: "1.5rem" }}>

          {/* ── 1. Most Improved ─────────────────────────────────────────────── */}
          <div style={{ background: CARD, borderRadius: "16px", padding: "1.3rem 1.4rem", marginBottom: "1.2rem" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: "0.9rem" }}>
              <span style={{ fontSize: "1.2rem" }}>🚀</span>
              <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.95rem", flex: 1 }}>Top 5 Most Improved</div>
              <div style={{ fontSize: "0.72rem", color: "#888" }}>CI gain over program</div>
            </div>
            {mostImproved.length === 0 ? (
              <div style={{ color: "#aaa", fontSize: "0.85rem", textAlign: "center", padding: "1rem 0" }}>
                Need at least 2 check-ins per member to calculate improvement
              </div>
            ) : (
              mostImproved.map(({ m, firstCI, latestCI, gain, weekCount }, idx) => {
                const tier = getCapacityTier(latestCI);
                return (
                  <div key={m.id} onClick={() => setSelected(m)}
                    style={{ display: "flex", alignItems: "center", gap: "0.9rem", padding: "0.7rem 0.9rem",
                      borderRadius: "10px", marginBottom: "0.4rem", cursor: "pointer",
                      background: idx === 0 ? "#fffbf0" : "#fafafa",
                      border: idx === 0 ? "1px solid #f5d060" : "1px solid #eee",
                      transition: "background 0.15s" }}
                    onMouseEnter={e => e.currentTarget.style.background = idx === 0 ? "#fff5d6" : "#f0f0f0"}
                    onMouseLeave={e => e.currentTarget.style.background = idx === 0 ? "#fffbf0" : "#fafafa"}>
                    {/* Rank badge */}
                    <div style={{ width: "28px", height: "28px", borderRadius: "50%", flexShrink: 0,
                      background: idx === 0 ? "#f0a500" : idx === 1 ? "#aaa" : idx === 2 ? "#b87333" : "#e0e0e0",
                      color: "#fff", fontWeight: "bold", fontSize: "0.78rem",
                      display: "flex", alignItems: "center", justifyContent: "center" }}>
                      {idx + 1}
                    </div>
                    {/* Avatar */}
                    <div style={{ width: "34px", height: "34px", borderRadius: "50%", flexShrink: 0,
                      background: `hsl(${((m.name || "").charCodeAt(0) * 37) % 360}, 55%, 55%)`,
                      color: "#fff", fontWeight: "bold", fontSize: "0.82rem",
                      display: "flex", alignItems: "center", justifyContent: "center" }}>
                      {(m.name || "?").charAt(0).toUpperCase()}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.9rem" }}>{m.name}</div>
                      <div style={{ fontSize: "0.72rem", color: tier.color, fontWeight: "bold", display:"flex", alignItems:"center", gap:"0.25rem" }}><GBSCIcon name={tier.icon} size={12} color={tier.color} strokeWidth={0}/>{tier.tier}</div>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <div style={{ display: "flex", alignItems: "center", gap: "0.35rem", justifyContent: "flex-end" }}>
                        <span style={{ fontSize: "0.82rem", color: "#aaa" }}>{firstCI}</span>
                        <span style={{ color: G, fontSize: "0.82rem" }}>→</span>
                        <span style={{ fontWeight: "bold", fontSize: "1rem", color: DARK }}>{latestCI}</span>
                      </div>
                      <div style={{ fontSize: "0.72rem", color: G, fontWeight: "bold" }}>▲ +{gain} pts</div>
                    </div>
                  </div>
                );
              })
            )}
          </div>

          {/* ── 2. Tier Distribution ─────────────────────────────────────────── */}
          <div style={{ background: CARD, borderRadius: "16px", padding: "1.3rem 1.4rem", marginBottom: "1.2rem" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: "0.9rem" }}>
              <span style={{ fontSize: "1.2rem" }}>🏅</span>
              <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.95rem", flex: 1 }}>Capacity Tier Distribution</div>
              <div style={{ fontSize: "0.72rem", color: "#888" }}>{totalWithCI} member{totalWithCI !== 1 ? "s" : ""} ranked</div>
            </div>
            {totalWithCI === 0 ? (
              <div style={{ color: "#aaa", fontSize: "0.85rem", textAlign: "center", padding: "1rem 0" }}>
                No members with check-ins yet
              </div>
            ) : (
              tierCounts.map(({ name, emoji, color, count, members: mNames }) => {
                const pct = Math.round((count / totalWithCI) * 100);
                return (
                  <div key={name} style={{ marginBottom: "0.75rem" }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: "0.25rem" }}>
                      <span style={{ fontSize: "0.85rem", fontWeight: "bold", color }}>
                        {emoji} {name}
                      </span>
                      <span style={{ fontSize: "0.82rem", color: count > 0 ? DARK : "#ccc", fontWeight: "bold" }}>
                        {count} {count > 0 ? `(${pct}%)` : ""}
                      </span>
                    </div>
                    <div style={{ background: "#eee", borderRadius: "999px", height: "10px", overflow: "hidden" }}>
                      <div style={{ background: color, width: `${pct}%`, height: "100%", borderRadius: "999px", transition: "width 0.5s ease", minWidth: count > 0 ? "4px" : "0" }} />
                    </div>
                    {count > 0 && (
                      <div style={{ fontSize: "0.68rem", color: "#aaa", marginTop: "0.2rem" }}>
                        {mNames.slice(0, 6).join(", ")}{mNames.length > 6 ? ` +${mNames.length - 6} more` : ""}
                      </div>
                    )}
                  </div>
                );
              })
            )}
          </div>

          {/* ── 3. Community CI Trend ────────────────────────────────────────── */}
          <div style={{ background: CARD, borderRadius: "16px", padding: "1.3rem 1.4rem", marginBottom: "1.2rem" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: "0.9rem" }}>
              <span style={{ fontSize: "1.2rem" }}>📊</span>
              <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.95rem", flex: 1 }}>GBSC Community Capacity Index</div>
              <div style={{ fontSize: "0.72rem", color: "#888" }}>Avg CI by week</div>
            </div>
            {communityTrend.length < 2 ? (
              <div style={{ color: "#aaa", fontSize: "0.85rem", textAlign: "center", padding: "1rem 0" }}>
                Trend will appear once members have 2+ weeks of check-ins
              </div>
            ) : (
              <>
                {/* Current avg callout */}
                <div style={{ display: "flex", gap: "1rem", marginBottom: "1rem" }}>
                  <div style={{ background: `${G}12`, border: `1px solid ${G}44`, borderRadius: "10px", padding: "0.7rem 1rem", textAlign: "center" }}>
                    <div style={{ fontSize: "1.6rem", fontWeight: "bold", color: G }}>{communityTrend[communityTrend.length - 1].avg}</div>
                    <div style={{ fontSize: "0.7rem", color: "#888" }}>Current Avg CI</div>
                  </div>
                  {communityTrend.length >= 2 && (() => {
                    const delta = communityTrend[communityTrend.length-1].avg - communityTrend[0].avg;
                    return (
                      <div style={{ background: delta >= 0 ? `${G}12` : "#fff4ee", border: `1px solid ${delta >= 0 ? G+"44" : "#fad0b8"}`, borderRadius: "10px", padding: "0.7rem 1rem", textAlign: "center" }}>
                        <div style={{ fontSize: "1.6rem", fontWeight: "bold", color: delta >= 0 ? G : "#e07030" }}>
                          {delta >= 0 ? "+" : ""}{delta}
                        </div>
                        <div style={{ fontSize: "0.7rem", color: "#888" }}>Since Week 1</div>
                      </div>
                    );
                  })()}
                  <div style={{ background: "#f7f7f7", border: "1px solid #eee", borderRadius: "10px", padding: "0.7rem 1rem", textAlign: "center" }}>
                    <div style={{ fontSize: "1.6rem", fontWeight: "bold", color: DARK }}>{communityTrend[communityTrend.length-1].count}</div>
                    <div style={{ fontSize: "0.7rem", color: "#888" }}>Members tracked</div>
                  </div>
                </div>
                {/* SVG Chart */}
                <div style={{ overflowX: "auto" }}>
                  <svg viewBox={`0 0 ${chartW} ${chartH}`} style={{ width: "100%", maxWidth: chartW, display: "block" }}>
                    {/* Grid lines */}
                    {[0, 0.25, 0.5, 0.75, 1].map(f => {
                      const yv = minY + f * rangeY;
                      const yp = cy(yv);
                      return (
                        <g key={f}>
                          <line x1={padL} y1={yp} x2={chartW - padR} y2={yp} stroke="#e8e8e8" strokeWidth="1" />
                          <text x={padL - 4} y={yp + 4} fontSize="9" fill="#aaa" textAnchor="end">{Math.round(yv)}</text>
                        </g>
                      );
                    })}
                    {/* Area fill */}
                    {areaPath && <path d={areaPath} fill={`${G}18`} />}
                    {/* Line */}
                    {linePath && <path d={linePath} fill="none" stroke={G} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />}
                    {/* Data points + labels */}
                    {trendPoints.map((p, i) => (
                      <g key={i}>
                        <circle cx={cx(i)} cy={cy(p.avg)} r="4" fill={G} stroke="#fff" strokeWidth="1.5" />
                        <text x={cx(i)} y={padT + plotH + 16} fontSize="9" fill="#888" textAnchor="middle">W{p.week}</text>
                        <text x={cx(i)} y={cy(p.avg) - 8} fontSize="9" fill={DARK} textAnchor="middle" fontWeight="bold">{p.avg}</text>
                      </g>
                    ))}
                  </svg>
                </div>
              </>
            )}
          </div>

          {/* ── 4. Pod Captains ──────────────────────────────────────────────── */}
          <div style={{ background: CARD, borderRadius: "16px", padding: "1.3rem 1.4rem", marginBottom: "1.2rem" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: "0.9rem" }}>
              <span style={{ fontSize: "1.2rem" }}>⭐</span>
              <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.95rem", flex: 1 }}>Pod Captains</div>
              <button onClick={downloadCaptainsCSV}
                disabled={captains.length === 0}
                style={{ background: captains.length > 0 ? G : "#ccc", color: "#fff", border: "none",
                  borderRadius: "8px", padding: "0.3rem 0.85rem", fontSize: "0.75rem",
                  fontWeight: "bold", cursor: captains.length > 0 ? "pointer" : "not-allowed" }}>
                ↓ Export CSV
              </button>
            </div>
            {captains.length === 0 ? (
              <div style={{ color: "#aaa", fontSize: "0.85rem", textAlign: "center", padding: "1rem 0" }}>
                No captains assigned yet — set them in the Pods tab
              </div>
            ) : (
              <div style={{ overflowX: "auto" }}>
                <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.85rem" }}>
                  <thead>
                    <tr style={{ background: "#f5f5f5" }}>
                      {["Name", "Email", "Pod", "Week"].map(h => (
                        <th key={h} style={{ padding: "0.5rem 0.75rem", textAlign: "left", fontWeight: "bold",
                          color: "#666", fontSize: "0.75rem", letterSpacing: "0.04em", borderBottom: "2px solid #eee" }}>
                          {h}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {captains.map(({ member: m, pod: p }, i) => {
                      const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
                      return (
                        <tr key={m.id} style={{ background: i % 2 ? "#fafafa" : "#fff" }}
                          onClick={() => setSelected(m)}
                          onMouseEnter={e => e.currentTarget.style.background = "#f0f7ec"}
                          onMouseLeave={e => e.currentTarget.style.background = i % 2 ? "#fafafa" : "#fff"}
                          style={{ cursor: "pointer", background: i % 2 ? "#fafafa" : "#fff" }}>
                          <td style={{ padding: "0.55rem 0.75rem", fontWeight: "bold", color: DARK }}>
                            <div style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                              <span style={{ fontSize: "0.9rem" }}>⭐</span>
                              {m.name}
                            </div>
                          </td>
                          <td style={{ padding: "0.55rem 0.75rem", color: "#555" }}>{m.email || "—"}</td>
                          <td style={{ padding: "0.55rem 0.75rem" }}>
                            <span style={{ background: `${G}18`, border: `1px solid ${G}44`, borderRadius: "999px",
                              padding: "0.15rem 0.55rem", fontSize: "0.78rem", color: DARK }}>
                              {p.emoji} {p.name}
                            </span>
                          </td>
                          <td style={{ padding: "0.55rem 0.75rem", color: "#888", fontSize: "0.8rem" }}>
                            {checks.length}/8
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>

          {/* ── 5. Community Consistency ─────────────────────────────────── */}
          {(() => {
            const membersWithChecks = members.filter(m => (m.weeklyChecks || []).some(c => c && !c.isBaseline));
            if (!membersWithChecks.length) return null;
            // Count each member's latest check week status
            let fullCapWeeks = 0, mewWeeks = 0, resetWeeks = 0, totalLatestChecks = 0;
            membersWithChecks.forEach(m => {
              const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
              if (!checks.length) return;
              const latest = checks[checks.length - 1];
              const ws = getWeekStatus(latest.score);
              totalLatestChecks++;
              if (ws?.status === "Full Capacity Week") fullCapWeeks++;
              else if (ws?.status === "Minimum Effective Week") mewWeeks++;
              else resetWeeks++;
            });
            // Count ALL historical weeks across all members
            let allMEW = 0, allFull = 0;
            members.forEach(m => {
              (m.weeklyChecks || []).filter(c => c && !c.isBaseline).forEach(c => {
                const ws = getWeekStatus(c.score);
                if (ws?.status === "Full Capacity Week") allFull++;
                else if (ws?.status === "Minimum Effective Week") allMEW++;
              });
            });
            const successfulThisWeek = fullCapWeeks + mewWeeks;
            const pctSuccess = totalLatestChecks ? Math.round((successfulThisWeek / totalLatestChecks) * 100) : 0;
            return (
              <div style={{ background: CARD, borderRadius: "16px", padding: "1.3rem 1.4rem", marginBottom: "1.2rem" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: "1rem" }}>
                  <span style={{ fontSize: "1.2rem" }}>📅</span>
                  <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.95rem", flex: 1 }}>Community Consistency</div>
                  <div style={{ fontSize: "0.72rem", color: "#888" }}>{totalLatestChecks} active member{totalLatestChecks !== 1 ? "s" : ""}</div>
                </div>
                {/* This week success rate */}
                <div style={{ marginBottom: "1rem" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: "0.3rem" }}>
                    <span style={{ fontSize: "0.82rem", color: DARK, fontWeight: "bold" }}>Successful Weeks This Week</span>
                    <span style={{ fontSize: "1.1rem", fontWeight: "bold", color: pctSuccess >= 70 ? G : pctSuccess >= 50 ? "#e09020" : "#e05030" }}>{pctSuccess}%</span>
                  </div>
                  <div style={{ background: "#eee", borderRadius: "999px", height: "10px", overflow: "hidden" }}>
                    <div style={{ background: pctSuccess >= 70 ? G : pctSuccess >= 50 ? "#e09020" : "#e05030", width: `${pctSuccess}%`, height: "100%", borderRadius: "999px", transition: "width 0.5s ease" }} />
                  </div>
                  <div style={{ display: "flex", gap: "0.5rem", marginTop: "0.6rem", flexWrap: "wrap" }}>
                    <span style={{ fontSize: "0.72rem", background: "#1a7a0015", color: "#1a7a00", borderRadius: "999px", padding: "0.15rem 0.65rem", fontWeight: "bold" }}>🔥 Full Capacity: {fullCapWeeks}</span>
                    <span style={{ fontSize: "0.72rem", background: `${G}15`, color: "#2a7a14", borderRadius: "999px", padding: "0.15rem 0.65rem", fontWeight: "bold" }}>✅ Min Effective: {mewWeeks}</span>
                    <span style={{ fontSize: "0.72rem", background: "#e0503015", color: "#e05030", borderRadius: "999px", padding: "0.15rem 0.65rem", fontWeight: "bold" }}>🔁 Reset: {resetWeeks}</span>
                  </div>
                </div>
                {/* All-time totals */}
                <div style={{ borderTop: "1px solid #f0f0f0", paddingTop: "0.8rem" }}>
                  <div style={{ fontSize: "0.72rem", color: "#aaa", marginBottom: "0.5rem", fontWeight: "bold", letterSpacing: "0.05em" }}>ALL-TIME TOTALS</div>
                  <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "0.5rem" }}>
                    {[
                      { label: "Full Capacity Weeks", val: allFull, color: "#1a7a00" },
                      { label: "Min Effective Weeks", val: allMEW, color: G },
                    ].map(({ label, val, color }) => (
                      <div key={label} style={{ background: "#f8f8f8", borderRadius: "10px", padding: "0.7rem", textAlign: "center" }}>
                        <div style={{ fontSize: "1.4rem", fontWeight: "bold", color }}>{val}</div>
                        <div style={{ fontSize: "0.68rem", color: "#888", marginTop: "0.1rem", lineHeight: 1.3 }}>{label}</div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            );
          })()}

          {/* ── 6. Role Distribution ─────────────────────────────────────────── */}
          {(() => {
            const membersWithChecks = members.filter(m => (m.weeklyChecks || []).some(c => c && !c.isBaseline));
            if (!membersWithChecks.length) return null;
            let performers = 0, builders = 0, stabilizers = 0, resets = 0;
            membersWithChecks.forEach(m => {
              const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
              if (!checks.length) return;
              const latest = checks[checks.length - 1];
              const role = getCapacityRole(latest.score);
              if (role?.role === "Performer") performers++;
              else if (role?.role === "Builder") builders++;
              else if (role?.role === "Stabilizer") stabilizers++;
              else resets++;
            });
            const total = performers + builders + stabilizers + resets;
            if (!total) return null;
            const pct = n => Math.round((n / total) * 100);
            const roles = [
              { label: "Performer", count: performers, color: "#1a7a00", emoji: "🔥" },
              { label: "Builder",   count: builders,   color: G,         emoji: "📈" },
              { label: "Stabilizer",count: stabilizers,color: "#e09020", emoji: "🛡️" },
              { label: "Reset",     count: resets,     color: "#e05030", emoji: "🔁" },
            ];
            return (
              <div style={{ background: CARD, borderRadius: "16px", padding: "1.3rem 1.4rem", marginBottom: "1.2rem" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: "1rem" }}>
                  <span style={{ fontSize: "1.2rem" }}>🎭</span>
                  <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.95rem", flex: 1 }}>Role Distribution</div>
                  <div style={{ fontSize: "0.72rem", color: "#888" }}>{total} member{total !== 1 ? "s" : ""} this week</div>
                </div>
                {roles.map(({ label, count, color, emoji }) => {
                  const p = pct(count);
                  return (
                    <div key={label} style={{ marginBottom: "0.75rem" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: "0.25rem" }}>
                        <span style={{ fontSize: "0.85rem", fontWeight: "bold", color }}>
                          {emoji} {label}
                        </span>
                        <span style={{ fontSize: "0.82rem", color: count > 0 ? DARK : "#ccc", fontWeight: "bold" }}>
                          {count} {count > 0 ? `(${p}%)` : ""}
                        </span>
                      </div>
                      <div style={{ background: "#eee", borderRadius: "999px", height: "10px", overflow: "hidden" }}>
                        <div style={{ background: color, width: `${p}%`, height: "100%", borderRadius: "999px", transition: "width 0.5s ease", minWidth: count > 0 ? "4px" : "0" }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })()}

        </div>
      </div>
    );
  }

  // ── PODS TAB ──────────────────────────────────────────────────────────────
  if (coachTab === "pods") {
    // Pod editor modal
    if (editingPod !== null && podDraft) {
      const assignedElsewhere = (memberId) =>
        pods.some(p => p.id !== podDraft.id && p.memberIds.includes(memberId));
      const toggleMember = (memberId) => {
        setPodDraft(d => {
          const removing = d.memberIds.includes(memberId);
          return {
            ...d,
            memberIds: removing
              ? d.memberIds.filter(id => id !== memberId)
              : d.memberIds.length >= 5 ? d.memberIds : [...d.memberIds, memberId],
            captainId: removing && d.captainId === memberId ? null : d.captainId
          };
        });
      };
      const setCaptain = (memberId) => {
        setPodDraft(d => ({ ...d, captainId: d.captainId === memberId ? null : memberId }));
      };
      const shuffleName = () => {
        const usedNames = pods.filter(p => p.id !== podDraft.id).map(p => p.name);
        const available = POD_NAMES.filter(n => !usedNames.includes(n.name) && n.name !== podDraft.name);
        const pick = available.length > 0
          ? available[Math.floor(Math.random() * available.length)]
          : POD_NAMES[Math.floor(Math.random() * POD_NAMES.length)];
        setPodDraft(d => ({ ...d, name: pick.name, emoji: pick.emoji }));
      };
      return (
        <div style={{ minHeight: "100vh", background: PAGE_BG, fontFamily: "Georgia, serif" }}>
          {hdr}
          <div style={{ maxWidth: "520px", margin: "0 auto", padding: "1.5rem" }}>
            <button onClick={() => { setEditingPod(null); setPodDraft(null); }}
              style={{ background: "none", border: "none", color: G, cursor: "pointer", fontWeight: "bold", marginBottom: "1rem" }}>
              ← Back to Pods
            </button>
            <div style={{ background: CARD, borderRadius: "16px", padding: "1.5rem", marginBottom: "1.2rem" }}>
              <div style={{ fontWeight: "bold", color: DARK, marginBottom: "1rem", fontSize: "1.05rem" }}>
                {editingPod === "new" ? "Create New Pod" : "Edit Pod"}
              </div>

              {/* Pod name + emoji row */}
              <div style={{ display: "flex", alignItems: "center", gap: "0.8rem", marginBottom: "1rem" }}>
                <div style={{ fontSize: "2rem" }}>{podDraft.emoji}</div>
                <input
                  value={podDraft.name}
                  onChange={e => setPodDraft(d => ({ ...d, name: e.target.value }))}
                  style={{ flex: 1, padding: "0.6rem 0.9rem", border: "1.5px solid #ddd", borderRadius: "8px", fontSize: "1rem" }}
                  placeholder="Pod name..."
                />
                <button onClick={shuffleName}
                  style={{ background: DARK, color: "#fff", border: "none", borderRadius: "8px", padding: "0.6rem 0.9rem", cursor: "pointer", fontSize: "0.85rem", whiteSpace: "nowrap" }}>
                  🎲 Shuffle
                </button>
              </div>
              <div style={{ fontSize: "0.75rem", color: "#888", marginBottom: "1.2rem" }}>
                Select 4–5 members, then tap ⭐ to assign a captain. Members in another pod are dimmed.
              </div>

              {/* Member list */}
              <div style={{ maxHeight: "380px", overflowY: "auto" }}>
                {members.filter(m => m.id !== "__pods__" && m.name).map(m => {
                  const inPod = podDraft.memberIds.includes(m.id);
                  const elsewhere = assignedElsewhere(m.id);
                  const atMax = podDraft.memberIds.length >= 5 && !inPod;
                  const disabled = elsewhere || atMax;
                  const isCaptain = podDraft.captainId === m.id;
                  return (
                    <div key={m.id}
                      style={{
                        display: "flex", alignItems: "center", gap: "0.8rem",
                        padding: "0.7rem 0.9rem", borderRadius: "10px",
                        marginBottom: "0.4rem",
                        opacity: disabled ? 0.4 : 1,
                        background: inPod ? `${G}18` : "#f8f8f8",
                        border: isCaptain ? `1.5px solid #f0a500` : inPod ? `1.5px solid ${G}` : "1.5px solid transparent",
                        transition: "all 0.15s"
                      }}>
                      {/* Avatar — click to toggle membership */}
                      <div onClick={() => !disabled && toggleMember(m.id)}
                        style={{
                          width: "32px", height: "32px", borderRadius: "50%", flexShrink: 0,
                          background: `hsl(${(m.name.charCodeAt(0) * 37) % 360}, 55%, 55%)`,
                          color: "#fff", fontWeight: "bold", fontSize: "0.8rem",
                          display: "flex", alignItems: "center", justifyContent: "center",
                          cursor: disabled ? "default" : "pointer"
                        }}>
                        {m.name.charAt(0).toUpperCase()}
                      </div>
                      {/* Name — click to toggle membership */}
                      <div onClick={() => !disabled && toggleMember(m.id)} style={{ flex: 1, cursor: disabled ? "default" : "pointer" }}>
                        <div style={{ fontWeight: inPod ? "bold" : "normal", color: DARK, fontSize: "0.9rem", display: "flex", alignItems: "center", gap: "0.4rem" }}>
                          {m.name}
                          {isCaptain && <span style={{ fontSize: "0.7rem", color: "#f0a500", fontWeight: "bold" }}>⭐ Captain</span>}
                        </div>
                        <div style={{ fontSize: "0.72rem", color: "#888" }}>
                          {elsewhere ? "In another pod" : `Week ${(m.weeklyChecks || []).filter(c => c && !c.isBaseline).length}/8`}
                        </div>
                      </div>
                      {/* Captain crown button — only shown for in-pod members */}
                      {inPod && (
                        <button
                          onClick={e => { e.stopPropagation(); setCaptain(m.id); }}
                          title={isCaptain ? "Remove as captain" : "Make captain"}
                          style={{
                            background: isCaptain ? "#f0a500" : "#eee",
                            border: "none", borderRadius: "6px",
                            width: "28px", height: "28px", cursor: "pointer",
                            fontSize: "0.85rem", display: "flex", alignItems: "center", justifyContent: "center",
                            flexShrink: 0, transition: "background 0.15s"
                          }}>
                          ⭐
                        </button>
                      )}
                      {/* Checkmark */}
                      <div onClick={() => !disabled && toggleMember(m.id)}
                        style={{
                          width: "22px", height: "22px", borderRadius: "50%",
                          background: inPod ? G : "#ddd",
                          display: "flex", alignItems: "center", justifyContent: "center",
                          cursor: disabled ? "default" : "pointer", flexShrink: 0
                        }}>
                        {inPod && <span style={{ color: "#fff", fontSize: "0.7rem", fontWeight: "bold" }}>✓</span>}
                      </div>
                    </div>
                  );
                })}
              </div>

              <div style={{ marginTop: "1rem", fontSize: "0.8rem", color: podDraft.memberIds.length >= 4 ? G : "#888", fontWeight: "bold" }}>
                {podDraft.memberIds.length}/5 members selected
                {podDraft.memberIds.length < 4 && " (need at least 4)"}
              </div>
            </div>

            <button onClick={handleSavePod}
              disabled={podSaving || podDraft.memberIds.length < 2 || !podDraft.name.trim()}
              style={{
                width: "100%", background: podDraft.memberIds.length < 2 ? "#ccc" : G,
                color: "#fff", border: "none", borderRadius: "12px",
                padding: "1rem", fontSize: "1rem", fontWeight: "bold",
                cursor: podDraft.memberIds.length < 2 ? "not-allowed" : "pointer"
              }}>
              {podSaving ? "Saving..." : editingPod === "new" ? "✓ Create Pod" : "✓ Save Changes"}
            </button>
          </div>
        </div>
      );
    }

    // Pods list view
    return (
      <div style={{ minHeight: "100vh", background: PAGE_BG, fontFamily: "Georgia, serif" }}>
        {hdr}
        <div style={{ maxWidth: "700px", margin: "0 auto", padding: "1.5rem" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "1.2rem" }}>
            <div>
              <div style={{ fontWeight: "bold", fontSize: "1.1rem", color: DARK }}>Support Pods</div>
              <div style={{ fontSize: "0.8rem", color: "#888", marginTop: "0.2rem" }}>
                {pods.length} pod{pods.length !== 1 ? "s" : ""} · {pods.reduce((s, p) => s + p.memberIds.length, 0)} members assigned
              </div>
            </div>
            {pods.length < 20 && (
              <button onClick={startNewPod}
                style={{ background: G, color: "#fff", border: "none", borderRadius: "10px", padding: "0.6rem 1.2rem", fontSize: "0.9rem", fontWeight: "bold", cursor: "pointer" }}>
                + New Pod
              </button>
            )}
          </div>

          {pods.length === 0 && (
            <div style={{ textAlign: "center", padding: "3rem", color: "#aaa" }}>
              <div style={{ fontSize: "2.5rem", marginBottom: "0.8rem" }}>🫛</div>
              <div style={{ fontWeight: "bold", color: DARK, marginBottom: "0.5rem" }}>No pods yet</div>
              <div style={{ fontSize: "0.85rem", marginBottom: "1.2rem" }}>Group members into pods of 4–5 for peer support.</div>
              <button onClick={startNewPod}
                style={{ background: G, color: "#fff", border: "none", borderRadius: "10px", padding: "0.7rem 1.5rem", fontSize: "0.95rem", fontWeight: "bold", cursor: "pointer" }}>
                Create First Pod
              </button>
            </div>
          )}

          {pods.map(pod => {
            const podMemberObjs = members.filter(m => pod.memberIds.includes(m.id));
            return (
              <div key={pod.id} style={{ background: CARD, borderRadius: "14px", padding: "1.2rem 1.4rem", marginBottom: "0.9rem", border: "1.5px solid transparent" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "0.8rem", marginBottom: "0.8rem" }}>
                  <span style={{ fontSize: "1.6rem" }}>{pod.emoji}</span>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: "bold", color: DARK, fontSize: "1rem" }}>{pod.name}</div>
                    <div style={{ fontSize: "0.75rem", color: "#888" }}>
                      {pod.memberIds.length} member{pod.memberIds.length !== 1 ? "s" : ""}
                      {pod.captainId && (() => {
                        const cap = members.find(m => m.id === pod.captainId);
                        return cap ? <span style={{ color: "#f0a500", fontWeight: "bold" }}> · ⭐ {cap.name}</span> : null;
                      })()}
                    </div>
                  </div>
                  <button onClick={() => startEditPod(pod)}
                    style={{ background: "none", border: `1.5px solid ${G}`, color: G, borderRadius: "8px", padding: "0.4rem 0.9rem", fontSize: "0.8rem", fontWeight: "bold", cursor: "pointer", marginRight: "0.4rem" }}>
                    Edit
                  </button>
                  <button onClick={() => handleDeletePod(pod.id)}
                    style={{ background: "none", border: "1.5px solid #e74c3c", color: "#e74c3c", borderRadius: "8px", padding: "0.4rem 0.9rem", fontSize: "0.8rem", cursor: "pointer" }}>
                    ✕
                  </button>
                </div>
                <div style={{ display: "flex", flexWrap: "wrap", gap: "0.5rem" }}>
                  {podMemberObjs.map(m => {
                    const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
                    return (
                      <div key={m.id} style={{
                        display: "flex", alignItems: "center", gap: "0.5rem",
                        background: pod.captainId === m.id ? "#fff8e6" : PAGE_BG,
                        border: pod.captainId === m.id ? "1.5px solid #f0a500" : "1.5px solid transparent",
                        borderRadius: "999px",
                        padding: "0.3rem 0.8rem", fontSize: "0.8rem"
                      }}>
                        <div style={{
                          width: "20px", height: "20px", borderRadius: "50%", flexShrink: 0,
                          background: `hsl(${(m.name.charCodeAt(0) * 37) % 360}, 55%, 55%)`,
                          color: "#fff", fontWeight: "bold", fontSize: "0.6rem",
                          display: "flex", alignItems: "center", justifyContent: "center"
                        }}>
                          {m.name.charAt(0).toUpperCase()}
                        </div>
                        {pod.captainId === m.id && <span style={{ fontSize: "0.7rem" }}>⭐</span>}
                        <span style={{ color: DARK, fontWeight: pod.captainId === m.id ? "bold" : "normal" }}>{m.name}</span>
                        <span style={{ color: "#aaa", fontSize: "0.72rem" }}>W{checks.length}</span>
                      </div>
                    );
                  })}
                  {pod.memberIds.filter(id => !members.find(m => m.id === id)).length > 0 && (
                    <div style={{ fontSize: "0.72rem", color: "#e07030", padding: "0.3rem 0" }}>
                      ⚠ {pod.memberIds.filter(id => !members.find(m => m.id === id)).length} member(s) no longer exist
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: "100vh", background: PAGE_BG, fontFamily: "Georgia, serif" }}>
      {hdr}
      <div style={{ maxWidth: "700px", margin: "0 auto", padding: "1.5rem" }}>
        {/* Gym summary */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "0.8rem", marginBottom: "1.5rem" }}>
          {[
            { label: "Total Members", val: members.length },
            { label: "Active (w/ check-ins)", val: members.filter(m => (m.weeklyChecks || []).some(c => c && !c.isBaseline)).length },
            { label: "Avg Capacity Index", val: avgCI ?? "—" },
          ].map(({ label, val }) => (
            <div key={label} style={{ background: DARK, borderRadius: "12px", padding: "1rem", textAlign: "center" }}>
              <div style={{ fontSize: "1.8rem", fontWeight: "bold", color: G }}>{val}</div>
              <div style={{ fontSize: "0.75rem", color: "#aaa" }}>{label}</div>
            </div>
          ))}
        </div>

        <input placeholder="🔍 Search members..." value={search} onChange={e => setSearch(e.target.value)}
          style={{ width: "100%", padding: "0.7rem 1rem", border: "1.5px solid #ddd", borderRadius: "8px", fontSize: "1rem", boxSizing: "border-box", marginBottom: "1rem" }} />

        {/* ── Export panel ── */}
        <div style={{ background: CARD, borderRadius: "14px", padding: "1.2rem 1.4rem", marginBottom: "1.5rem", display: "flex", alignItems: "center", gap: "1rem", flexWrap: "wrap" }}>
          <div style={{ flex: 1, minWidth: "160px" }}>
            <div style={{ fontWeight: "bold", color: DARK, fontSize: "0.9rem" }}>📥 Export Challenge Data</div>
            <div style={{ fontSize: "0.75rem", color: "#888", marginTop: "0.2rem" }}>All members · all check-ins · all scores</div>
          </div>
          <div style={{ display: "flex", gap: "0.6rem", flexShrink: 0 }}>
            <button onClick={downloadCSV} disabled={members.length === 0}
              style={{ background: members.length === 0 ? "#ccc" : G, color: "#fff", border: "none", borderRadius: "8px", padding: "0.55rem 1.1rem", fontSize: "0.85rem", fontWeight: "bold", cursor: members.length === 0 ? "not-allowed" : "pointer", whiteSpace: "nowrap" }}>
              {downloading ? "Preparing…" : "⬇ CSV"}
            </button>
            <button onClick={downloadJSON} disabled={members.length === 0}
              style={{ background: members.length === 0 ? "#ccc" : DARK, color: "#fff", border: "none", borderRadius: "8px", padding: "0.55rem 1.1rem", fontSize: "0.85rem", fontWeight: "bold", cursor: members.length === 0 ? "not-allowed" : "pointer", whiteSpace: "nowrap" }}>
              ⬇ JSON
            </button>
          </div>
        </div>

        {filtered.length === 0 && (
          <div style={{ textAlign: "center", color: "#aaa", padding: "3rem" }}>No members enrolled yet.</div>
        )}
        {filtered.map(m => {
          const checks = (m.weeklyChecks || []).filter(c => c && !c.isBaseline);
          const habitAvg = checks.length ? Math.round(checks.reduce((s,c)=>s+c.score,0)/checks.length) : null;
          const ci = habitAvg !== null ? calcCapacityIndex(m.vo2Score_pre, m.gripScore_pre, habitAvg) : null;
          const tier = ci !== null ? getCapacityTier(ci) : null;
          const latestCheck = checks[checks.length - 1];
          const mRole = latestCheck ? getCapacityRole(latestCheck.score) : null;
          const mWS   = latestCheck ? getWeekStatus(latestCheck.score) : null;
          return (
            <div key={m.id} onClick={() => setSelected(m)}
              style={{ display: "flex", justifyContent: "space-between", alignItems: "center", background: CARD, borderRadius: "12px", padding: "1rem 1.2rem", marginBottom: "0.7rem", cursor: "pointer", border: "1.5px solid transparent", transition: "border 0.2s" }}
              onMouseEnter={e => e.currentTarget.style.border = `1.5px solid ${G}`}
              onMouseLeave={e => e.currentTarget.style.border = "1.5px solid transparent"}>
              <div>
                <div style={{ fontWeight: "bold", color: DARK }}>{m.name}</div>
                <div style={{ fontSize: "0.8rem", color: "#888" }}>Week {checks.length}/8 · Age {m.age}</div>
                {tier && <div style={{ fontSize: "0.8rem", color: tier.color, fontWeight: "bold", display:"flex", alignItems:"center", gap:"0.3rem" }}><GBSCIcon name={tier.icon} size={14} color={tier.color} strokeWidth={0}/>{tier.tier}</div>}
                {!tier && <div style={{ fontSize: "0.8rem", color: "#bbb" }}>No check-ins yet</div>}
                {mRole && mWS && (
                  <div style={{ display: "flex", gap: "0.4rem", marginTop: "0.3rem", flexWrap: "wrap" }}>
                    <span style={{ fontSize: "0.68rem", fontWeight: "bold", color: mRole.color, background: mRole.color + "15", borderRadius: "999px", padding: "0.1rem 0.55rem" }}>
                      {mRole.emoji} {mRole.role}
                    </span>
                    <span style={{ fontSize: "0.68rem", fontWeight: "bold", color: mWS.color, background: mWS.color + "15", borderRadius: "999px", padding: "0.1rem 0.55rem" }}>
                      {mWS.emoji} {mWS.status}
                    </span>
                  </div>
                )}
              </div>
              <div style={{ textAlign: "right" }}>
                {ci !== null && <div style={{ fontSize: "2rem", fontWeight: "bold", color: G }}>{ci}</div>}
                {ci === null && <div style={{ fontSize: "0.85rem", color: "#bbb" }}>—</div>}
                <div style={{ fontSize: "0.75rem", color: "#aaa" }}>Capacity Index</div>
              </div>
            </div>
          );
        })}

        {/* ── Wipe all data ── */}
        {members.length > 0 && (
          <div style={{ marginTop: "2rem", paddingTop: "1.5rem", borderTop: "1px solid #eee" }}>
            {!confirmWipeAll ? (
              <button onClick={() => setConfirmWipeAll(true)}
                style={{ width: "100%", background: "none", border: "2px solid #e74c3c", color: "#e74c3c", borderRadius: "12px", padding: "0.8rem", fontSize: "0.9rem", fontWeight: "bold", cursor: "pointer" }}>
                🗑 Wipe All Member Data
              </button>
            ) : (
              <div style={{ background: "#fff5f5", border: "2px solid #e74c3c", borderRadius: "12px", padding: "1.2rem", textAlign: "center" }}>
                <div style={{ fontWeight: "bold", color: "#e74c3c", marginBottom: "0.5rem" }}>⚠️ This will delete ALL {members.length} member profiles permanently.</div>
                <div style={{ fontSize: "0.85rem", color: "#888", marginBottom: "1rem" }}>Use this to clear test data before the real program starts.</div>
                <div style={{ display: "flex", gap: "0.8rem" }}>
                  <button onClick={() => setConfirmWipeAll(false)}
                    style={{ flex: 1, background: "#eee", border: "none", borderRadius: "8px", padding: "0.7rem", fontWeight: "bold", cursor: "pointer", color: DARK }}>
                    Cancel
                  </button>
                  <button onClick={deleteAllMembers}
                    style={{ flex: 1, background: "#e74c3c", border: "none", borderRadius: "8px", padding: "0.7rem", fontWeight: "bold", cursor: "pointer", color: "#fff" }}>
                    Yes, Delete All
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
